import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [user, setUser] = useState(null);
  const [students, setStudents] = useState([]);
  const [view, setView] = useState("dashboard");
  const [search, setSearch] = useState("");
  const [id, setId] = useState("");
  const [pass, setPass] = useState("");

  useEffect(() => {
    if (user?.role === 'admin') loadData();
  }, [user]);

  const loadData = () => axios.get('http://localhost:3000/admin/students').then(res => setStudents(res.data));

  const updateStudent = (sid, data) => {
    axios.put(`http://localhost:3000/admin/update/${encodeURIComponent(sid)}`, data).then(() => loadData());
  };

  const filtered = students.filter(s => s.id.toLowerCase().includes(search.toLowerCase()));

  if (!user) {
    return (
      <div style={styles.loginPage}>
        <div style={styles.loginCard}>
          <h2 style={{color: '#1a73e8'}}>UOB PORTAL 2026</h2>
          <input placeholder="BCS/S.../2026 ama admin" onChange={e => setId(e.target.value)} style={styles.input} />
          <input type="password" placeholder="Password" onChange={e => setPass(e.target.value)} style={styles.input} />
          <button onClick={() => {
            axios.post('http://localhost:3000/login', { id, password: pass })
            .then(res => setUser(res.data)).catch(() => alert("Login Failed!"));
          }} style={styles.loginBtn}>LOGIN</button>
        </div>
      </div>
    );
  }

  // --- ADMIN INTERFACE ---
  if (user.role === 'admin') {
    return (
      <div style={{ display: 'flex', height: '100vh', background: '#f0f2f5' }}>
        <div style={styles.sidebar}>
          <h2 style={{fontSize: '18px', borderBottom: '1px solid #444'}}>ADMIN 2026</h2>
          <button onClick={() => setView("exam")} style={view === "exam" ? styles.activeBtn : styles.menuBtn}>📝 Geli Imtixaanka</button>
          <button onClick={() => setView("attendance")} style={view === "attendance" ? styles.activeBtn : styles.menuBtn}>📅 Xadiriska</button>
          <button onClick={() => setView("fees")} style={view === "fees" ? styles.activeBtn : styles.menuBtn}>💰 Lacagaha</button>
          <button onClick={() => setUser(null)} style={styles.logoutBtn}>Logout</button>
        </div>
        <div style={{ flex: 1, padding: '30px', overflowY: 'auto' }}>
          <div style={{display: 'flex', justifyContent: 'space-between', marginBottom: '20px'}}>
            <h2>MAAMULKA: {view.toUpperCase()}</h2>
            <input placeholder="🔍 Raadi ID Arday..." onChange={e => setSearch(e.target.value)} style={styles.search} />
          </div>
          <table style={styles.table}>
            <thead>
              <tr style={{background: '#1a73e8', color: 'white'}}>
                <th>ID</th><th>Magaca</th>
                {view === "exam" ? <th>Bil 1 | Mid-Term | Bil 3 | Final</th> : <th>Action</th>}
                <th>Attendance</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map(s => (
                <tr key={s.id} style={{textAlign: 'center', borderBottom: '1px solid #ddd'}}>
                  <td style={{padding: '12px'}}>{s.id}</td>
                  <td>{s.magaca}</td>
                  <td>
                    {view === "exam" ? (
                      <div style={{display: 'flex', gap: '5px', justifyContent: 'center'}}>
                        <input type="number" placeholder="B1" style={styles.miniIn} onBlur={e => updateStudent(s.id, {imtixaan: {...s.imtixaan, bilaha1: e.target.value}})} defaultValue={s.imtixaan.bilaha1} />
                        <input type="number" placeholder="Mid" style={styles.miniIn} onBlur={e => updateStudent(s.id, {imtixaan: {...s.imtixaan, midterm: e.target.value}})} defaultValue={s.imtixaan.midterm} />
                        <input type="number" placeholder="B3" style={styles.miniIn} onBlur={e => updateStudent(s.id, {imtixaan: {...s.imtixaan, bilaha3: e.target.value}})} defaultValue={s.imtixaan.bilaha3} />
                        <input type="number" placeholder="Fin" style={styles.miniIn} onBlur={e => updateStudent(s.id, {imtixaan: {...s.imtixaan, final: e.target.value}})} defaultValue={s.imtixaan.final} />
                      </div>
                    ) : view === "attendance" ? (
                      <div>
                        <button onClick={() => updateStudent(s.id, {joogay: s.joogay + 1})} style={styles.btnGreen}>√</button>
                        <button onClick={() => updateStudent(s.id, {maqnaa: s.maqnaa + 1})} style={styles.btnRed}>X</button>
                      </div>
                    ) : (
                      <select onChange={e => updateStudent(s.id, {lacagta: e.target.value})} defaultValue={s.lacagta}>
                        <option value="Ma bixin">Ma bixin</option><option value="Bixiyey">Bixiyey</option>
                      </select>
                    )}
                  </td>
                  <td style={{fontWeight: 'bold'}}>{Math.round((s.joogay / (s.joogay + s.maqnaa || 1)) * 100)}%</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    );
  }

  // --- STUDENT INTERFACE (VIEW ONLY) ---
  return (
    <div style={styles.studentDashboard}>
      <div style={styles.card}>
        <h1 style={{color: '#1a73e8'}}>WARBIXINTA ARDAYGA 2026</h1>
        <hr/>
        <h3>Kursiga: {user.id}</h3>
        <div style={styles.timeline}>
          <div style={styles.timeBox}><h4>Bilaha 1aad</h4><p>{user.imtixaan.bilaha1}%</p></div>
          <div style={styles.timeBox}><h4>Mid-Term</h4><p>{user.imtixaan.midterm}%</p></div>
          <div style={styles.timeBox}><h4>Bilaha 3aad</h4><p>{user.imtixaan.bilaha3}%</p></div>
          <div style={styles.timeBox}><h4>Final Exam</h4><p>{user.imtixaan.final}%</p></div>
        </div>
        <div style={{marginTop: '30px', display: 'flex', justifyContent: 'space-around'}}>
           <div><h4>Xadiriska Guud</h4><h2 style={{color: 'green'}}>{Math.round((user.joogay / (user.joogay + user.maqnaa || 1)) * 100)}%</h2></div>
           <div><h4>Status-ka Lacagta</h4><h2 style={{color: user.lacagta === 'Bixiyey' ? 'green' : 'red'}}>{user.lacagta}</h2></div>
        </div>
        <button onClick={() => setUser(null)} style={styles.logoutBtn}>LOGOUT</button>
      </div>
    </div>
  );
}

const styles = {
  sidebar: { width: '250px', background: '#1c2833', color: 'white', padding: '25px', display: 'flex', flexDirection: 'column', gap: '15px' },
  menuBtn: { padding: '15px', background: 'transparent', color: '#abb2b9', border: 'none', textAlign: 'left', cursor: 'pointer', borderRadius: '8px' },
  activeBtn: { padding: '15px', background: '#1a73e8', color: 'white', border: 'none', textAlign: 'left', cursor: 'pointer', borderRadius: '8px' },
  loginPage: { height: '100vh', display: 'flex', justifyContent: 'center', alignItems: 'center', background: '#f4f6f9' },
  loginCard: { background: 'white', padding: '40px', borderRadius: '20px', boxShadow: '0 10px 30px rgba(0,0,0,0.1)', textAlign: 'center' },
  input: { display: 'block', width: '300px', padding: '15px', margin: '10px 0', borderRadius: '10px', border: '1px solid #ddd' },
  loginBtn: { width: '100%', padding: '15px', background: '#1a73e8', color: 'white', border: 'none', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer' },
  table: { width: '100%', borderCollapse: 'collapse', background: 'white', borderRadius: '10px', overflow: 'hidden' },
  miniIn: { width: '45px', padding: '8px', textAlign: 'center', border: '1px solid #ddd', borderRadius: '5px' },
  search: { padding: '12px', width: '300px', borderRadius: '10px', border: '1px solid #ddd' },
  studentDashboard: { padding: '50px', background: '#eef2f3', minHeight: '100vh', textAlign: 'center' },
  card: { background: 'white', padding: '40px', borderRadius: '25px', display: 'inline-block', width: '90%', maxWidth: '900px', boxShadow: '0 15px 35px rgba(0,0,0,0.1)' },
  timeline: { display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '15px', marginTop: '30px' },
  timeBox: { padding: '20px', background: '#f8f9fa', borderRadius: '15px', borderBottom: '5px solid #1a73e8' },
  btnGreen: { background: '#27ae60', color: 'white', border: 'none', padding: '8px 15px', borderRadius: '5px', cursor: 'pointer', marginRight: '5px' },
  btnRed: { background: '#e74c3c', color: 'white', border: 'none', padding: '8px 15px', borderRadius: '5px', cursor: 'pointer' },
  logoutBtn: { marginTop: '30px', padding: '12px 30px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer' }
};

export default App;
